DROP TABLE IF EXISTS `system_config`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `system_config` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT,
  `config_key` varchar(64) CHARACTER SET utf8mb4 NOT NULL COMMENT '配置键',
  `config_value` varchar(255) CHARACTER SET utf8mb4 NOT NULL COMMENT '配置值',
  `value_type` varchar(20) CHARACTER SET utf8mb4 NOT NULL DEFAULT 'STRING' COMMENT 'STRING/INT/BOOLEAN/TIME',
  `category` varchar(32) CHARACTER SET utf8mb4 NOT NULL DEFAULT 'RESERVATION' COMMENT '分类',
  `config_name` varchar(64) CHARACTER SET utf8mb4 NOT NULL COMMENT '配置名称',
  `description` varchar(255) CHARACTER SET utf8mb4 DEFAULT NULL COMMENT '配置说明',
  `editable` tinyint(4) NOT NULL DEFAULT '1' COMMENT '是否允许后台修改',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_system_config_key` (`config_key`)
) ENGINE=InnoDB AUTO_INCREMENT=25 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

